//Components...
import MobileNav from "./Mobile-nav";

//React router...
import { Outlet, NavLink } from "react-router-dom";

//Styles...
import "../styles/Discovery.scss";

export default function Discovery() {
  //const dispatch = useDispatch()

  const handleAnimeClick = () => {
    localStorage.setItem("currentAnimePage", "1");
    //dispatch(nameInput({type: e.currentTarget.getAttribute("data-name")}))
  };
  const handleMangaClick = () => {
    localStorage.setItem("currentAnimePage", "1");
    //dispatch(nameInput({type: e.currentTarget.getAttribute("data-name")}))
  };

  return (
    <section className="discovery-page">
      <MobileNav />
      <nav className="discovery-nav">
        <NavLink onClick={handleAnimeClick} to="anime">
          Anime
        </NavLink>
        <NavLink onClick={handleMangaClick} to="manga">
          Manga
        </NavLink>
        <NavLink to="manhwa">Manhwa</NavLink>
        <NavLink to="manhua">Manhua</NavLink>
      </nav>
      <Outlet />
    </section>
  );
}
